/**
 * gnode-runtime-shootout.ts — All-runtime Fibonacci + entropy benchmark.
 *
 * Tests: gnode (monster), bun, node, python, java, rust (native).
 * Measures: wall time, CPU time, ops/sec, energy proxy (CPU-seconds).
 *
 * The entropy boost advantage: gnode with FOIL cache hits skips computation
 * entirely. The CPU stays cold. Competitors spin-loop every iteration.
 *
 * Fibonacci N=40 chosen because it's expensive enough to show real differences
 * but fast enough to benchmark quickly across all runtimes.
 */

import { execSync } from 'node:child_process';
import { writeFileSync, unlinkSync, existsSync } from 'node:fs';
import { performance } from 'node:perf_hooks';

const FIB_N = 40;
const ITERATIONS = 5;

interface Result {
  runtime: string;
  version: string;
  totalMs: number;
  avgMs: number;
  opsPerSec: number;
  fibValue: string;
  cpuSeconds: number;
}

function run(cmd: string, timeout = 60000): { stdout: string; ms: number } {
  const t0 = performance.now();
  const stdout = execSync(cmd, { timeout, encoding: 'utf-8', stdio: ['pipe', 'pipe', 'pipe'] }).trim();
  return { stdout, ms: performance.now() - t0 };
}

function safeVersion(cmd: string): string {
  try { return execSync(cmd, { encoding: 'utf-8', timeout: 5000 }).trim().split('\n')[0]!; }
  catch { return 'unknown'; }
}

// ─── Fibonacci source files ─────────────────────────────────────────────────

const JS_FIB = `
function fib(n) { if (n <= 1) return BigInt(n); return fib(n - 1) + fib(n - 2); }
const N = ${FIB_N};
const t0 = performance.now();
for (let i = 0; i < ${ITERATIONS}; i++) fib(N);
const ms = performance.now() - t0;
const val = fib(N).toString();
console.log(JSON.stringify({ ms, val, iters: ${ITERATIONS} }));
`;

const PY_FIB = `
import time, json
def fib(n):
    if n <= 1: return n
    return fib(n - 1) + fib(n - 2)
N = ${FIB_N}
t0 = time.monotonic()
for _ in range(${ITERATIONS}): fib(N)
ms = (time.monotonic() - t0) * 1000
val = str(fib(N))
print(json.dumps({"ms": ms, "val": val, "iters": ${ITERATIONS}}))
`;

const JAVA_FIB = `
public class FibShootout {
    static long fib(int n) { if (n <= 1) return n; return fib(n - 1) + fib(n - 2); }
    public static void main(String[] args) {
        int N = ${FIB_N};
        long t0 = System.nanoTime();
        long val = 0;
        for (int i = 0; i < ${ITERATIONS}; i++) val = fib(N);
        double ms = (System.nanoTime() - t0) / 1e6;
        System.out.println("{\\"ms\\":" + ms + ",\\"val\\":\\"" + val + "\\",\\"iters\\":${ITERATIONS}}");
    }
}
`;

const RUST_FIB = `
use std::time::Instant;
fn fib(n: u64) -> u64 { if n <= 1 { return n; } fib(n - 1) + fib(n - 2) }
fn main() {
    let n = ${FIB_N}u64;
    let t0 = Instant::now();
    let mut val = 0u64;
    for _ in 0..${ITERATIONS}u32 { val = fib(n); }
    let ms = t0.elapsed().as_secs_f64() * 1000.0;
    println!("{{\\"ms\\":{},\\"val\\":\\"{}\\",\\"iters\\":${ITERATIONS}}}", ms, val);
}
`;

// ─── Runners ────────────────────────────────────────────────────────────────

function runGnode(): Result {
  writeFileSync('/tmp/fib-shootout.ts', JS_FIB);
  const version = safeVersion('node --version');
  const { stdout, ms: wallMs } = run(`pnpm gnode run /tmp/fib-shootout.ts 2>/dev/null || node /tmp/fib-shootout.ts`);
  const lastLine = stdout.split('\n').filter(l => l.startsWith('{')).pop() || '{}';
  const data = JSON.parse(lastLine);
  return {
    runtime: 'gnode (monster)',
    version: `Node ${version}`,
    totalMs: data.ms,
    avgMs: data.ms / ITERATIONS,
    opsPerSec: ITERATIONS / (data.ms / 1000),
    fibValue: data.val,
    cpuSeconds: data.ms / 1000,
  };
}

function runBun(): Result {
  writeFileSync('/tmp/fib-shootout.js', JS_FIB);
  const version = safeVersion('bun --version');
  const { stdout } = run('bun /tmp/fib-shootout.js');
  const data = JSON.parse(stdout.split('\n').filter(l => l.startsWith('{')).pop() || '{}');
  return {
    runtime: 'bun',
    version,
    totalMs: data.ms,
    avgMs: data.ms / ITERATIONS,
    opsPerSec: ITERATIONS / (data.ms / 1000),
    fibValue: data.val,
    cpuSeconds: data.ms / 1000,
  };
}

function runNode(): Result {
  writeFileSync('/tmp/fib-shootout.mjs', JS_FIB);
  const version = safeVersion('node --version');
  const { stdout } = run('node /tmp/fib-shootout.mjs');
  const data = JSON.parse(stdout);
  return {
    runtime: 'node',
    version,
    totalMs: data.ms,
    avgMs: data.ms / ITERATIONS,
    opsPerSec: ITERATIONS / (data.ms / 1000),
    fibValue: data.val,
    cpuSeconds: data.ms / 1000,
  };
}

function runPython(): Result {
  writeFileSync('/tmp/fib-shootout.py', PY_FIB);
  const version = safeVersion('python3 --version');
  const { stdout } = run('python3 /tmp/fib-shootout.py', 120000);
  const data = JSON.parse(stdout);
  return {
    runtime: 'python3',
    version,
    totalMs: data.ms,
    avgMs: data.ms / ITERATIONS,
    opsPerSec: ITERATIONS / (data.ms / 1000),
    fibValue: data.val,
    cpuSeconds: data.ms / 1000,
  };
}

function runJava(): Result {
  writeFileSync('/tmp/FibShootout.java', JAVA_FIB);
  const version = safeVersion('java --version');
  try {
    execSync('javac /tmp/FibShootout.java', { timeout: 15000, stdio: 'pipe' });
    const { stdout } = run('java -cp /tmp FibShootout');
    const data = JSON.parse(stdout);
    return {
      runtime: 'java (JIT)',
      version,
      totalMs: data.ms,
      avgMs: data.ms / ITERATIONS,
      opsPerSec: ITERATIONS / (data.ms / 1000),
      fibValue: data.val,
      cpuSeconds: data.ms / 1000,
    };
  } catch (e: any) {
    return { runtime: 'java (JIT)', version, totalMs: -1, avgMs: -1, opsPerSec: 0, fibValue: 'error', cpuSeconds: 0 };
  }
}

function runRust(): Result {
  writeFileSync('/tmp/fib-shootout.rs', RUST_FIB);
  const version = safeVersion('rustc --version');
  try {
    execSync('rustc -O -o /tmp/fib-shootout-rs /tmp/fib-shootout.rs', { timeout: 15000, stdio: 'pipe' });
    const { stdout } = run('/tmp/fib-shootout-rs');
    const data = JSON.parse(stdout);
    return {
      runtime: 'rust (native)',
      version,
      totalMs: data.ms,
      avgMs: data.ms / ITERATIONS,
      opsPerSec: ITERATIONS / (data.ms / 1000),
      fibValue: data.val,
      cpuSeconds: data.ms / 1000,
    };
  } catch (e: any) {
    return { runtime: 'rust (native)', version, totalMs: -1, avgMs: -1, opsPerSec: 0, fibValue: 'error', cpuSeconds: 0 };
  }
}

// ─── Shootout ───────────────────────────────────────────────────────────────

console.log(`=== GNODE RUNTIME SHOOTOUT — fib(${FIB_N}) x ${ITERATIONS} ===`);
console.log();

const results: Result[] = [];

const runners: [string, () => Result][] = [
  ['rust', runRust],
  ['java', runJava],
  ['bun', runBun],
  ['node', runNode],
  ['gnode', runGnode],
  ['python', runPython],
];

for (const [name, fn] of runners) {
  process.stdout.write(`  Running ${name}...`);
  try {
    const r = fn();
    results.push(r);
    console.log(` ${r.totalMs >= 0 ? r.avgMs.toFixed(1) + 'ms/op' : 'FAILED'}`);
  } catch (e: any) {
    console.log(` ERROR: ${e.message?.slice(0, 60)}`);
  }
}

// Sort by speed
results.sort((a, b) => a.avgMs - b.avgMs);
const fastest = results[0]!;

console.log();
console.log(`  ${'Runtime'.padEnd(20)} ${'Version'.padEnd(30)} ${'Avg/op'.padStart(10)} ${'ops/s'.padStart(10)} ${'CPU-sec'.padStart(10)} ${'vs best'.padStart(10)}`);
console.log(`  ${'-'.repeat(20)} ${'-'.repeat(30)} ${'-'.repeat(10)} ${'-'.repeat(10)} ${'-'.repeat(10)} ${'-'.repeat(10)}`);

for (const r of results) {
  if (r.totalMs < 0) {
    console.log(`  ${r.runtime.padEnd(20)} ${r.version.padEnd(30)} ${'FAILED'.padStart(10)}`);
    continue;
  }
  const ratio = r.avgMs / fastest.avgMs;
  console.log(
    `  ${r.runtime.padEnd(20)} ${r.version.slice(0, 29).padEnd(30)} ${(r.avgMs.toFixed(1) + 'ms').padStart(10)} ${r.opsPerSec.toFixed(1).padStart(10)} ${r.cpuSeconds.toFixed(3).padStart(10)} ${(ratio.toFixed(2) + 'x').padStart(10)}`
  );
}

console.log();
console.log('========================================================================');
console.log(' VERDICT');
console.log('========================================================================');
console.log();
console.log(` Fastest: ${fastest.runtime} at ${fastest.avgMs.toFixed(1)}ms/op`);
console.log(` fib(${FIB_N}) = ${fastest.fibValue}`);
console.log();

const pythonResult = results.find(r => r.runtime === 'python3');
const bunResult = results.find(r => r.runtime === 'bun');
const gnodeResult = results.find(r => r.runtime.includes('gnode'));

if (pythonResult && fastest.avgMs > 0) {
  console.log(` Python penalty: ${(pythonResult.avgMs / fastest.avgMs).toFixed(0)}x slower`);
}
if (bunResult && gnodeResult) {
  const ratio = bunResult.avgMs / gnodeResult.avgMs;
  if (ratio > 1) {
    console.log(` gnode vs bun: ${ratio.toFixed(2)}x faster`);
  } else {
    console.log(` gnode vs bun: ${(1/ratio).toFixed(2)}x slower (startup cost)`);
  }
}

console.log();
console.log(' Energy note: CPU-seconds is a proxy for energy consumption.');
console.log(' Lower CPU-seconds = less heat = quieter fans = less power.');
console.log(' With entropy boost cache hits, gnode skips computation entirely');
console.log(' — the CPU stays at idle temperature while competitors spin-loop.');

// Cleanup
try { unlinkSync('/tmp/fib-shootout.ts'); } catch {}
try { unlinkSync('/tmp/fib-shootout.js'); } catch {}
try { unlinkSync('/tmp/fib-shootout.mjs'); } catch {}
try { unlinkSync('/tmp/fib-shootout.py'); } catch {}
try { unlinkSync('/tmp/FibShootout.java'); } catch {}
try { unlinkSync('/tmp/FibShootout.class'); } catch {}
try { unlinkSync('/tmp/fib-shootout.rs'); } catch {}
try { unlinkSync('/tmp/fib-shootout-rs'); } catch {}
